#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int f[100010],in[100010],in1[100010];
int main()
{
    int n,m,q;
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[v].push_back(u);
        in1[u]++;
    }
    while(q--)
    {
        int s,t;
        scanf("%d%d",&s,&t);
        for(int i=1;i<=n;i++)
        {
            in[i]=in1[i];
            f[i]=0;
        }
        queue<int> q;
        for(int i=1;i<=n;i++)
        {
            if(i==t||!in[i])
            {
                f[i]=-1;
                q.push(i);
            }
        }
        while(!q.empty())
        {
            int t=q.front();
            q.pop();
            for(int i:mp[t])
            {
                if(f[i]!=0)
                {
                    continue;
                }
                if(f[t]==1)
                {
                    in[i]--;
                    if(in[i]==0)
                    {
                        q.push(i);
                        f[i]=-1;
                    }
                }
                else
                {
                    q.push(i);
                    f[i]=1;
                }
            }
        }
        printf("%d\n",f[s]);
    }
    return 0;
}
